package com.izonehub.stores.inventory;
import com.izonehub.stores.common.BaseEntity;import com.izonehub.stores.item.Item;import com.izonehub.stores.store.Store;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.Instant;
@Entity @Table(uniqueConstraints=@UniqueConstraint(columnNames={"store_id","item_id"})) public class StoreInventory extends BaseEntity{@ManyToOne(optional=false,fetch=FetchType.LAZY) private Store store;@ManyToOne(optional=false,fetch=FetchType.LAZY) private Item item;@Column(nullable=false,precision=19,scale=4) private BigDecimal quantityOnHand=BigDecimal.ZERO;@Column(nullable=false,precision=19,scale=4) private BigDecimal quantityInTransit=BigDecimal.ZERO;@Column(nullable=false,precision=19,scale=4) private BigDecimal quantityFrozen=BigDecimal.ZERO;@Column(nullable=false) private Instant lastUpdated=Instant.now();protected StoreInventory(){} public StoreInventory(Store store,Item item){this.store=store;this.item=item;} public BigDecimal getQuantityOnHand(){return quantityOnHand;} public BigDecimal getQuantityInTransit(){return quantityInTransit;} public BigDecimal getQuantityFrozen(){return quantityFrozen;} public void receiveUsable(BigDecimal qty){requirePositive(qty);quantityOnHand=quantityOnHand.add(qty);touch();} public void dispatch(BigDecimal qty){requirePositive(qty); if(quantityOnHand.compareTo(qty)<0)throw new IllegalStateException("Insufficient on-hand stock"); quantityOnHand=quantityOnHand.subtract(qty); quantityInTransit=quantityInTransit.add(qty); touch();} public void receiveFromTransit(BigDecimal qty){requirePositive(qty); if(quantityInTransit.compareTo(qty)<0)throw new IllegalStateException("Insufficient in-transit stock"); quantityInTransit=quantityInTransit.subtract(qty); quantityOnHand=quantityOnHand.add(qty); touch();} public void freezeTransitVariance(BigDecimal qty){requirePositive(qty); if(quantityInTransit.compareTo(qty)<0)throw new IllegalStateException("Insufficient in-transit stock"); quantityInTransit=quantityInTransit.subtract(qty); quantityFrozen=quantityFrozen.add(qty); touch();} private static void requirePositive(BigDecimal qty){if(qty==null||qty.signum()<=0)throw new IllegalArgumentException("Quantity must be positive");} private void touch(){lastUpdated=Instant.now();}}
